Code.NativeIaC:
```bicep
// Bicep: Enable automatic failover on a Cosmos DB account
resource account 'Microsoft.DocumentDB/databaseAccounts@2025-10-15' = {
  name: '<example_resource_name>'
  location: resourceGroup().location
  kind: 'GlobalDocumentDB'
  properties: {
    databaseAccountOfferType: 'Standard'
    locations: [
      { locationName: '<primary_region>', failoverPriority: 0 }
      { locationName: '<secondary_region>', failoverPriority: 1 }
    ]
    enableAutomaticFailover: true // Critical: Promotes a secondary region during a primary region outage
  }
}
```

Code.Terraform:
```hcl
# Terraform: Enable automatic failover on a Cosmos DB account
resource "azurerm_cosmosdb_account" "<example_resource_name>" {
  name                = "<example_resource_name>"
  resource_group_name = "<example_resource_name>"
  location            = "<primary_region>"
  offer_type          = "Standard"
  kind                = "GlobalDocumentDB"

  geo_location {
    location          = "<primary_region>"
    failover_priority = 0
  }

  geo_location {
    location          = "<secondary_region>"
    failover_priority = 1
  }

  enable_automatic_failover = true # Critical: Promotes a secondary region during a primary region outage
}
```
